// ═══════════════════════════════════════════════════════
// Step 1: Konfiguration - Generische Parameter
// Unterstuetzt mehrere Mitbewerber gleichzeitig.
// Dokumente werden pro Versicherer als separate RAG-Collection
// in OpenWebUI hochgeladen (eine Collection pro Versicherer).
// ═══════════════════════════════════════════════════════

// --- ANPASSEN: Eigene Firma ---
const OWN_COMPANY_NAME = 'HanseMerkur';
const OWN_COMPANY_SHORT = 'HMR';
const OWN_PRODUCT_NAME = 'Seminar-Ruecktrittsversicherung';

// --- ANPASSEN: Mitbewerber (Array - beliebig viele Versicherer) ---
// Jeder Eintrag benoetigt eine eigene RAG-Collection-ID.
// Neue Versicherer einfach als weiteres Objekt hinzufuegen.
const COMPETITORS = [
  {
    name: 'ERGO Reiseversicherung',
    short: 'ERV',
    productName: 'Seminar-Versicherung',
    ragCollection: '32c26a09-6c8c-449c-a060-1146f20c0322'  // <-- ANPASSEN
  },
  // Weiteren Mitbewerber hier hinzufuegen:
  // {
  //   name: 'Allianz Travel',
  //   short: 'ALZ',
  //   productName: 'Seminar-Schutz',
  //   ragCollection: 'xxxxxxxx-xxxx-xxxx-xxxx-xxxxxxxxxxxx'  // <-- Collection ID
  // },
];

// --- ANPASSEN: API Einstellungen ---
const API_BASE_URL = 'https://aihubtest.hanse-merkur.de';
const RAG_ENDPOINT = '/api/v1/retrieval/query/collection';
const LLM_ENDPOINT = '/api/chat/completions';
const LLM_MODEL = 'qwen3:30b-a3b-instruct-2507-q8_0';
const RAG_TOP_K = 5;

return {
  config: {
    ownCompanyName: OWN_COMPANY_NAME,
    ownCompanyShort: OWN_COMPANY_SHORT,
    ownProductName: OWN_PRODUCT_NAME,
    competitors: COMPETITORS,
    apiBaseUrl: API_BASE_URL,
    ragEndpoint: RAG_ENDPOINT,
    llmEndpoint: LLM_ENDPOINT,
    llmModel: LLM_MODEL,
    ragTopK: RAG_TOP_K
  }
};

// ═══════════════════════════════════════════════════════
// Step 2: Eigene Hard Facts + RAG-Queries
// Generisch: Erstellt Fakten fuer ALLE konfigurierten Mitbewerber.
// Ergebnis: (Anzahl Fakten) × (Anzahl Mitbewerber) Items.
//
// ANPASSEN: Fakten fuer das jeweilige Produkt eintragen.
// Die Struktur bleibt generisch:
//   - own_data: eigene Leistung/Regelung
//   - rag_query: Frage an die Mitbewerber-AVB (nutze comp.name)
// ═══════════════════════════════════════════════════════

const config = $('01 - Config Parameters').first().json.config;

// Fakten als Funktion - wird einmal pro Mitbewerber aufgerufen
function buildFacts(comp) {
  return [
    {
      id: 1,
      kategorie: 'Produktuebersicht',
      aspekt: 'Produktname und Versicherungssparten',
      own_data: 'Seminar-Ruecktrittsversicherung. Sparte: Reise-Ruecktritt. Geltungsbereich: Europa.',
      rag_query: `Wie heisst das Produkt der ${comp.name} fuer Seminare? Welche Sparten sind enthalten? Welcher raeumliche Geltungsbereich gilt?`
    },
    {
      id: 2,
      kategorie: 'Produktuebersicht',
      aspekt: 'AVB-Version und Selbstbehalt',
      own_data: 'AVB: VB-RS 2021 (T-Seminar-D). Selbstbehalt: 20% bei ambulant behandelten Erkrankungen, mind. 25 EUR je versicherter Person.',
      rag_query: `Welche Versicherungsbedingungen (AVB) gelten fuer die ${comp.name} Seminar-Versicherung? Gibt es einen Selbstbehalt oder eine Selbstbeteiligung?`
    },
    {
      id: 3,
      kategorie: 'Versicherte Leistungen - Ruecktritt',
      aspekt: 'Stornokosten bei Nichtantritt des Seminars',
      own_data: 'Uebernahme der Stornokosten fuer das nicht angetretene Seminar.',
      rag_query: `Was erstattet die ${comp.name} Seminar-Versicherung bei Stornierung bzw. Ruecktritt vom Seminar? Werden auch Stornokosten fuer Seminarreihen und zusaetzliche Reiseleistungen uebernommen?`
    },
    {
      id: 4,
      kategorie: 'Versicherte Leistungen - Ruecktritt',
      aspekt: 'Verspaeteter Seminarantritt',
      own_data: 'Erstattung der Hinreise-Mehrkosten bis maximal zur Hoehe der Stornokosten, die bei einer Stornierung anfallen.',
      rag_query: `Was leistet die ${comp.name} Seminar-Versicherung bei verspaetem Seminarantritt? Werden Mehrkosten der Anreise und nicht genutzte Seminarleistungen erstattet?`
    },
    {
      id: 5,
      kategorie: 'Versicherte Leistungen - Ruecktritt',
      aspekt: 'Verspaetung oeffentliches Verkehrsmittel (mehr als 2 Stunden)',
      own_data: 'Erstattung der Hinreise-Mehrkosten bis maximal zur Hoehe der Stornokosten.',
      rag_query: `Was erstattet die ${comp.name} Seminar-Versicherung bei Verspaetung eines oeffentlichen Verkehrsmittels um mehr als zwei Stunden? Gibt es einen Verspaetungsschutz mit Betraegen fuer Anreise-Mehrkosten, Verpflegung und Unterkunft?`
    },
    {
      id: 6,
      kategorie: 'Versicherte Leistungen - Ruecktritt',
      aspekt: 'Panne oder Unfall des eigenen Kraftfahrzeugs',
      own_data: 'Nicht versichert. Nur wenn dadurch das versicherte Verkehrsmittel versaeumt wird: Erstattung der Hinreise-Mehrkosten bis maximal zur Hoehe der Stornokosten.',
      rag_query: `Was leistet die ${comp.name} Seminar-Versicherung bei Panne oder Unfall des eigenen Kraftfahrzeugs? Werden Kosten fuer nicht genutzte Leistungen, zusaetzliche Reisekosten oder ein Mietfahrzeug erstattet?`
    },
    {
      id: 7,
      kategorie: 'Versicherte Leistungen - Ruecktritt',
      aspekt: 'Umbuchung des Seminars',
      own_data: 'Erstattung der Umbuchungskosten bis maximal zur Hoehe der Stornokosten.',
      rag_query: `Sind Umbuchungsgebuehren bei der ${comp.name} Seminar-Versicherung versichert? Bis zu welcher Hoehe werden Umbuchungsgebuehren erstattet?`
    },
    {
      id: 8,
      kategorie: 'Reiseabbruch',
      aspekt: 'Abbruch des Seminars',
      own_data: 'Nicht versichert.',
      rag_query: `Was leistet die ${comp.name} Seminar-Versicherung bei Abbruch des Seminars? Werden anteilige Preise fuer nicht genutzte Leistungen und zusaetzliche Rueckreisekosten erstattet?`
    },
    {
      id: 9,
      kategorie: 'Reiseabbruch',
      aspekt: 'Verspaetete Rueckreise vom Seminar',
      own_data: 'Nicht versichert.',
      rag_query: `Hilft die ${comp.name} Seminar-Versicherung bei verspaeteter Rueckreise vom Seminar? Wird die Rueckreise organisiert oder ein Darlehen fuer Mehrkosten gewaehrt?`
    },
    {
      id: 10,
      kategorie: 'Reiseabbruch',
      aspekt: 'Verlaengerter Aufenthalt wegen stationaerer Behandlung',
      own_data: 'Nicht versichert.',
      rag_query: `Erstattet die ${comp.name} Seminar-Versicherung zusaetzliche Unterkunftskosten bei verlaengertem Aufenthalt wegen stationaerer Behandlung? Bis zu welchem Betrag?`
    },
    {
      id: 11,
      kategorie: 'Reiseabbruch',
      aspekt: 'Verlaengerter Aufenthalt wegen ambulanter Behandlung',
      own_data: 'Nicht versichert.',
      rag_query: `Erstattet die ${comp.name} Seminar-Versicherung zusaetzliche Unterkunftskosten bei verlaengertem Aufenthalt wegen ambulanter Behandlung? Bis zu welchem Betrag?`
    },
    {
      id: 12,
      kategorie: 'Reiseabbruch',
      aspekt: 'Verlaengerter Aufenthalt wegen Feuer oder Elementarereignissen',
      own_data: 'Nicht versichert.',
      rag_query: `Was leistet die ${comp.name} Seminar-Versicherung bei Feuer oder Elementarereignissen am Seminarort? Werden Mehrkosten fuer verlaengerten Aufenthalt und ausserplanmaessige Rueckreise erstattet?`
    },
    {
      id: 13,
      kategorie: 'Versicherte Ereignisse',
      aspekt: 'Nichtversetzung als Schueler oder Student',
      own_data: 'Versichert.',
      rag_query: `Ist Nichtversetzung eines Schuelers oder Studenten ein versichertes Ereignis bei der ${comp.name} Seminar-Versicherung? Welche Pruefungsereignisse sind versichert?`
    },
    {
      id: 14,
      kategorie: 'Versicherte Ereignisse',
      aspekt: 'Panne oder Unfall des Kraftfahrzeuges als Ruecktrittsgrund',
      own_data: 'Nicht direkt versichert. Nur indirekt wenn dadurch das versicherte Verkehrsmittel versaeumt wird.',
      rag_query: `Ist Panne oder Unfall des eigenen Kraftfahrzeugs ein versichertes Ereignis bei der ${comp.name} Seminar-Versicherung das zum Ruecktritt berechtigt?`
    },
    {
      id: 15,
      kategorie: 'Versicherte Ereignisse',
      aspekt: 'Erkrankung, Unfall oder Tod eines Hundes oder einer Katze',
      own_data: 'Versichert.',
      rag_query: `Ist die Erkrankung, der Unfall oder Tod eines Hundes oder einer Katze ein versichertes Ereignis bei der ${comp.name} Seminar-Versicherung?`
    },
    {
      id: 16,
      kategorie: 'Versicherte Ereignisse',
      aspekt: 'Feuer oder Elementarereignisse am Seminarort',
      own_data: 'Nicht versichert.',
      rag_query: `Sind Feuer oder Elementarereignisse am Seminarort versicherte Ereignisse bei der ${comp.name} Seminar-Versicherung? Was zaehlt als Elementarereignis?`
    },
    {
      id: 17,
      kategorie: 'Versicherte Ereignisse',
      aspekt: 'Absage durch den Veranstalter',
      own_data: 'Nicht versichert.',
      rag_query: `Ist die Absage des Seminars durch den Veranstalter ein versichertes Ereignis bei der ${comp.name} Seminar-Versicherung? Was wird in diesem Fall erstattet?`
    },
    {
      id: 18,
      kategorie: 'Weiteres',
      aspekt: 'Mitversicherung zusaetzlich gebuchter Reiseleistungen',
      own_data: 'Nicht versichert. Die Versicherungssumme sichert den Seminarpreis ab. Weitere Reiseleistungen muessen separat versichert werden.',
      rag_query: `Sind zusaetzlich gebuchte Reiseleistungen wie Anreise, Rueckreise und Unterkunft bei der ${comp.name} Seminar-Versicherung mitversichert? Welche zeitlichen Voraussetzungen gelten?`
    },
    {
      id: 19,
      kategorie: 'Weiteres',
      aspekt: 'Maximal versicherbarer Zeitraum und Seminarreihen',
      own_data: '1 Seminarreise, unabhaengig von der Seminardauer. Bei Seminarreihen muss jedes Modul separat abgeschlossen werden.',
      rag_query: `Wie lange ist der maximal versicherbare Zeitraum bei der ${comp.name} Seminar-Versicherung? Koennen Seminarreihen mit mehreren Teilveranstaltungen versichert werden? Bis zu welcher Dauer?`
    },
    {
      id: 20,
      kategorie: 'Weiteres',
      aspekt: 'Abschlussfristen',
      own_data: 'Abschluss bis 30 Tage vor Reisebeginn oder spaetestens bis zum 3. Werktag nach der Reisebuchung.',
      rag_query: `Welche Abschlussfristen gelten fuer die ${comp.name} Seminar-Versicherung? Bis wann muss der Versicherungsvertrag abgeschlossen werden?`
    }
  ];
}

// Kartesisches Produkt: Fakten × Mitbewerber
const items = [];
for (const competitor of config.competitors) {
  const facts = buildFacts(competitor);
  for (const fact of facts) {
    items.push({
      json: { ...fact, config: { ...config, currentCompetitor: competitor } }
    });
  }
}
return items;

// ═══════════════════════════════════════════════════════
// Step 4: Build RAG Request gegen Mitbewerber Collection
// Generisch: Verwendet die Collection-ID des aktuellen Mitbewerbers
// ═══════════════════════════════════════════════════════
const fact = $input.item.json;
const config = fact.config;
const competitor = config.currentCompetitor;

return {
  ...fact,
  retrievalRequestBody: JSON.stringify({
    collection_names: [competitor.ragCollection],
    query: fact.rag_query,
    k: config.ragTopK
  })
};

// ═══════════════════════════════════════════════════════
// Step 6: Parse RAG + Build LLM Comparison Request
// Generisch: Verwendet Config fuer Firmennamen und Modell
// Das LLM extrahiert Mitbewerber-Infos AUS DEM RAG
// ═══════════════════════════════════════════════════════
const ragResp = $input.item.json;
const fact = $('04 - Build RAG Request').item.json;
const config = fact.config;
const comp = config.currentCompetitor;

const docs = ragResp.documents?.[0] || [];
const metas = ragResp.metadatas?.[0] || [];
const dists = ragResp.distances?.[0] || [];

const contextChunks = docs.map((text, i) => {
  const meta = metas[i] || {};
  const source = (meta.name || meta.source || 'Unbekannt')
    .replace(/\.md\.txt$|\.txt$|\.md$/gi, '').replace(/_/g, ' ').trim();
  const dist = dists[i] || 'N/A';
  return '### Chunk ' + (i+1) + ' (Quelle: ' + source + ', Distance: ' + (typeof dist === 'number' ? dist.toFixed(3) : dist) + ')\n' + text;
}).join('\n\n');

const systemPrompt = `Du bist ein Versicherungsexperte, der AVB (Allgemeine Versicherungsbedingungen) analysiert und vergleicht.

Deine Aufgabe: Analysiere die bereitgestellten ${comp.name} AVB-Dokumente zu einem bestimmten Aspekt und vergleiche das Ergebnis mit der ${config.ownCompanyName} ${config.ownProductName}.

## WICHTIGE REGELN:
1. Extrahiere die ${comp.short}-Informationen AUSSCHLIESSLICH aus den bereitgestellten RAG-Dokumenten
2. Wenn die Dokumente KEINE Information zu diesem Aspekt enthalten, schreibe klar: "In den vorliegenden ${comp.short} AVB wurde hierzu keine Regelung gefunden."
3. ERFINDE KEINE Informationen - nur was in den Dokumenten steht
4. Sei praezise: Nenne konkrete Betraege, Prozentsaetze, Bedingungen, Paragraphen
5. Zitiere relevante Passagen aus den Dokumenten
6. Bewerte am Ende: Welcher Anbieter bietet hier den besseren Schutz? (${config.ownCompanyShort} besser / ${comp.short} besser / gleichwertig / nicht vergleichbar)
7. Antworte auf Deutsch in strukturierter Form

## Bereitgestellte ${comp.short} AVB-Dokumente:
` + contextChunks;

const userPrompt = `Analysiere und vergleiche folgenden Aspekt:

**Kategorie:** ${fact.kategorie}
**Aspekt:** ${fact.aspekt}

**${config.ownCompanyName} (${config.ownCompanyShort}) Regelung:**
${fact.own_data}

**Frage an die ${comp.short} AVB:**
${fact.rag_query}

Bitte:
1. Was genau sagen die ${comp.short} AVB-Dokumente zu diesem Aspekt? Zitiere relevante Stellen.
2. Fasse die ${comp.short}-Regelung in 1-3 Saetzen zusammen
3. Vergleiche mit der ${config.ownCompanyShort}-Regelung: Was sind die konkreten Unterschiede?
4. Bewertung: Wer bietet den besseren Schutz fuer diesen Aspekt?
5. **KURZFASSUNG:** Gib eine praegnante Kurzfassung der ${comp.short}-Regelung zu diesem Aspekt in maximal 100 Zeichen. Format: **KURZFASSUNG:** [Kurztext]`;

return {
  ...fact,
  ragContext: contextChunks,
  ragChunkCount: docs.length,
  ragDistances: dists.filter(d => typeof d === 'number').map(d => d.toFixed(3)),
  requestBody: JSON.stringify({
    model: config.llmModel,
    messages: [
      { role: 'system', content: systemPrompt },
      { role: 'user', content: userPrompt }
    ],
    temperature: 0.2,
    max_tokens: 1200,
    stream: false
  })
};

// ═══════════════════════════════════════════════════════
// Step 8: Parse LLM Result
// Generisch: Verwendet config fuer Firmennamen
// ═══════════════════════════════════════════════════════
const llmResp = $input.item.json;
const fact = $('06 - Parse RAG + Build LLM Request').item.json;
const config = fact.config;
const comp = config.currentCompetitor;

let answer = (llmResp.choices?.[0]?.message?.content || '')
  .replace(/<think>[\s\S]*?<\/think>/g, '')
  .trim();

// Bewertung extrahieren (letzter Satz oder Zeile mit 'besser'/'gleichwertig')
let bewertung = 'nicht ermittelt';
const bewertungMatch = answer.match(new RegExp(
  `(${config.ownCompanyShort}\\s+besser|${comp.short}\\s+besser|gleichwertig|nicht vergleichbar)`,
  'i'
));
if (bewertungMatch) {
  bewertung = bewertungMatch[1];
}

// Kurzfassung extrahieren
let kurzfassung = '';
const kurzMatch = answer.match(/\*\*KURZFASSUNG:\*\*\s*(.+)/i);
if (kurzMatch) {
  kurzfassung = kurzMatch[1].trim();
}

return {
  id: fact.id,
  kategorie: fact.kategorie,
  aspekt: fact.aspekt,
  own_data: fact.own_data,
  vergleich_aus_rag: answer,
  kurzfassung: kurzfassung,
  bewertung: bewertung,
  ragChunkCount: fact.ragChunkCount,
  ragDistances: fact.ragDistances,
  tokens: llmResp.usage?.total_tokens || 0,
  competitorShort: comp.short,
  competitorName: comp.name,
  config: config
};

// ═══════════════════════════════════════════════════════
// Step 9: Build Final Synthesis
// Sammelt ALLE Einzelvergleiche (alle Fakten × alle Mitbewerber)
// und baut den finalen LLM-Request fuer die Gesamtgegenueberstellung
// ═══════════════════════════════════════════════════════
const allItems = $input.all();
const results = allItems.map(item => item.json);
const config = results[0]?.config || {};

// Mitbewerber-Liste ermitteln (in Eingangsreihenfolge, dedupliziert)
const competitorMap = new Map();
for (const r of results) {
  if (!competitorMap.has(r.competitorShort)) {
    competitorMap.set(r.competitorShort, r.competitorName);
  }
}
const competitorNames = [...competitorMap.values()].join(', ');

// Abschnitte pro Mitbewerber gruppieren
const byCompetitor = new Map();
for (const r of results) {
  if (!byCompetitor.has(r.competitorShort)) {
    byCompetitor.set(r.competitorShort, []);
  }
  byCompetitor.get(r.competitorShort).push(r);
}

let comparisonSections = '';
for (const [compShort, compResults] of byCompetitor) {
  const compName = competitorMap.get(compShort);
  comparisonSections += '\n\n# Vergleich: ' + config.ownCompanyName + ' vs. ' + compName + '\n\n';
  for (const r of compResults) {
    comparisonSections +=
      '## ' + r.id + '. ' + r.kategorie + ' - ' + r.aspekt + '\n\n' +
      '**' + config.ownCompanyName + ' (' + config.ownCompanyShort + '):** ' + r.own_data + '\n\n' +
      '**' + compShort + ' laut RAG-Analyse:**\n' + r.vergleich_aus_rag + '\n\n' +
      '*RAG Chunks: ' + r.ragChunkCount + ' | Distances: ' + (r.ragDistances || []).join(', ') + '*\n\n---\n\n';
  }
}

const systemPrompt =
  'Du bist ein Versicherungsexperte der ' + config.ownCompanyName + '. ' +
  'Du erstellst eine Executive Summary eines AVB-Vergleichs zwischen der ' +
  config.ownCompanyName + ' ' + config.ownProductName + ' und folgenden Mitbewerbern: ' + competitorNames + '.\n\n' +
  'Die Einzelvergleiche basieren auf einer RAG-Analyse der Mitbewerber-AVB-Dokumente.\n\n' +
  '## Aufgabe:\n' +
  'Erstelle basierend auf den Einzelvergleichen eine strukturierte Gegenueberstellung mit:\n\n' +
  '1. **Executive Summary** (3-5 Saetze Gesamtbewertung)\n' +
  '2. **Vorteile ' + config.ownCompanyName + '** (Bullet-Liste: wo ' + config.ownCompanyShort + ' besser ist, mit konkreten Details)\n' +
  '3. **Vorteile Mitbewerber** (Bullet-Liste pro Mitbewerber: wo diese besser sind, mit konkreten Details)\n' +
  '4. **Gleichwertige Leistungen** (wo alle aehnlich sind)\n' +
  '5. **Kritische Unterschiede** (die wichtigsten Differenzen fuer die Kundenberatung)\n' +
  '6. **Handlungsempfehlung fuer Produktmanagement** (wo sollte ' + config.ownCompanyShort + ' nachbessern?)\n' +
  '7. **RAG-Qualitaetsbericht** (Welche Aspekte konnten gut aus den AVB ermittelt werden? ' +
  'Welche Aspekte konnten nicht aus den AVB ermittelt werden?)\n\n' +
  'Formatiere als Markdown. Sei praezise und faktenbasiert. ' +
  'Unterscheide klar zwischen Fakten aus den AVB und eigenen Bewertungen.';

const userPrompt =
  'Hier sind die ' + results.length + ' Einzelvergleiche ' +
  '(alle Fakten fuer alle Mitbewerber):\n\n' +
  comparisonSections + '\n\nErstelle bitte die Gesamtgegenueberstellung.';

return [{
  json: {
    allResults: results,
    resultCount: results.length,
    competitors: [...competitorMap.entries()].map(([short, name]) => ({ short, name })),
    config: config,
    requestBody: JSON.stringify({
      model: config.llmModel,
      messages: [
        { role: 'system', content: systemPrompt },
        { role: 'user', content: userPrompt }
      ],
      temperature: 0.3,
      max_tokens: 4000,
      stream: false
    })
  }
}];

// ═══════════════════════════════════════════════════════
// Step 11: Parse Final Synthesis + Build Output
// ═══════════════════════════════════════════════════════
const llmResp = $input.item.json;
const synthData = $('09 - Build Synthese-Request').item.json;
const config = synthData.config;

let synthesis = (llmResp.choices?.[0]?.message?.content || '')
  .replace(/<think>[\s\S]*?<\/think>/g, '')
  .trim();

const usage = llmResp.usage || {};

return {
  gesamtvergleich: synthesis,
  einzelvergleiche: synthData.allResults,
  anzahlFakten: synthData.resultCount,
  model: llmResp.model || config.llmModel,
  config: config,
  usage: {
    promptTokens: usage.prompt_tokens || 0,
    completionTokens: usage.completion_tokens || 0,
    totalTokens: usage.total_tokens || 0
  },
  timestamp: new Date().toISOString(),
  status: 'completed'
};

// ═══════════════════════════════════════════════════════
// Step 12: Report-Tabelle erstellen
// Erzeugt eine strukturierte Tabelle mit allen Ergebnissen.
// Unterstuetzt mehrere Mitbewerber: pro Mitbewerber eine Spalte.
// ═══════════════════════════════════════════════════════
const data = $input.item.json;
const config = data.config;
const einzelvergleiche = data.einzelvergleiche || [];
const competitors = data.competitors || [];

// Pivot: Fakten als Zeilen, Mitbewerber als Spalten
const byFact = new Map();
for (const e of einzelvergleiche) {
  if (!byFact.has(e.id)) {
    byFact.set(e.id, {
      Nr: e.id,
      Kategorie: e.kategorie,
      Aspekt: e.aspekt,
      [config.ownCompanyShort]: e.own_data
    });
  }
  const row = byFact.get(e.id);
  row[e.competitorShort] = e.kurzfassung || (e.vergleich_aus_rag || '').substring(0, 120) + ((e.vergleich_aus_rag || '').length > 120 ? '...' : '');
  row[e.competitorShort + '_Bewertung'] = e.bewertung || 'nicht ermittelt';
  row[e.competitorShort + '_RAG_Chunks'] = e.ragChunkCount;
  row[e.competitorShort + '_Tokens'] = e.tokens;
}

const reportTable = [...byFact.values()];

// Zusammenfassung pro Mitbewerber
const summaries = competitors.map(comp => {
  const compResults = einzelvergleiche.filter(e => e.competitorShort === comp.short);
  const ownBetter = compResults.filter(e => (e.bewertung || '').toLowerCase().includes(config.ownCompanyShort.toLowerCase() + ' besser')).length;
  const compBetter = compResults.filter(e => (e.bewertung || '').toLowerCase().includes(comp.short.toLowerCase() + ' besser')).length;
  const equal = compResults.filter(e => (e.bewertung || '').toLowerCase().includes('gleichwertig')).length;
  return {
    competitor: comp.name,
    competitorShort: comp.short,
    totalFacts: compResults.length,
    ownBetter,
    competitorBetter: compBetter,
    equal,
    unclear: compResults.length - ownBetter - compBetter - equal
  };
});

return {
  reportTable,
  summaries,
  competitors,
  gesamtvergleich: data.gesamtvergleich,
  config,
  meta: {
    model: data.model,
    usage: data.usage,
    timestamp: data.timestamp,
    status: data.status
  }
};

// ═══════════════════════════════════════════════════════
// Step 13: Final Report Output
// Erzeugt den vollstaendigen Report als Markdown
// Unterstuetzt mehrere Mitbewerber mit dynamischen Spalten.
// ═══════════════════════════════════════════════════════
const data = $input.all()[0].json;
const config = data.config;
const reportTable = data.reportTable || [];
const summaries = data.summaries || [];
const competitors = data.competitors || [];

// --- Dynamische Tabellen-Spalten ---
const compHeaders = competitors.flatMap(c => [c.short + ' (RAG)', c.short + ' Bewertung']);
const tableHeader = '| Nr | Kategorie | Aspekt | ' + config.ownCompanyShort + ' | ' + compHeaders.join(' | ') + ' |';
const sepCols = ['--', '---------', '------', '-'.repeat(config.ownCompanyShort.length + 2), ...compHeaders.map(h => '-'.repeat(h.length + 2))];
const tableSeparator = '|' + sepCols.join('|') + '|';
const tableRows = reportTable.map(r => {
  const compCells = competitors.flatMap(c => [
    r[c.short] || '',
    r[c.short + '_Bewertung'] || ''
  ]);
  return '| ' + r.Nr + ' | ' + r.Kategorie + ' | ' + r.Aspekt + ' | ' + (r[config.ownCompanyShort] || '') + ' | ' + compCells.join(' | ') + ' |';
}).join('\n');

// --- Zusammenfassungsblock pro Mitbewerber ---
const summaryBlock = summaries.map(s =>
  '### ' + s.competitor + ' (' + s.competitorShort + ')\n\n' +
  '| Metrik | Wert |\n' +
  '|--------|------|\n' +
  '| Verglichene Fakten | ' + s.totalFacts + ' |\n' +
  '| ' + config.ownCompanyShort + ' besser | ' + s.ownBetter + ' |\n' +
  '| ' + s.competitorShort + ' besser | ' + s.competitorBetter + ' |\n' +
  '| Gleichwertig | ' + s.equal + ' |\n' +
  '| Nicht eindeutig | ' + s.unclear + ' |\n'
).join('\n');

const competitorLine = competitors.map(c => c.name + ' (' + c.short + ')').join(', ');
const collectionLine = competitors.map(c => {
  const comp = (config.competitors || []).find(x => x.short === c.short);
  return c.short + ': ' + (comp ? comp.ragCollection : 'N/A');
}).join(', ');

const fullReport =
  '# AVB-Vergleich: ' + config.ownCompanyName + ' vs. ' + competitorLine + '\n\n' +
  '**Erstellt:** ' + data.meta.timestamp + '\n' +
  '**Modell:** ' + data.meta.model + '\n' +
  '**Verglichene Fakten:** ' + reportTable.length + '\n' +
  '**Gesamt-Tokens Synthese:** ' + data.meta.usage.totalTokens + '\n' +
  '**Mitbewerber-Collections:** ' + collectionLine + '\n\n' +
  '---\n\n' +
  '## Zusammenfassung\n\n' + summaryBlock + '\n\n' +
  '---\n\n' +
  '# Executive Summary und Gegenueberstellung\n\n' +
  data.gesamtvergleich + '\n\n' +
  '---\n\n' +
  '# Vergleichstabelle\n\n' +
  tableHeader + '\n' + tableSeparator + '\n' + tableRows + '\n';

// Return individual table rows for XLSX conversion
return reportTable.map(row => ({ json: row }));
